function lengthOfLongestSubstring(s: string): number {
  const lastIdx = new Map<string, number>();
  let l = 0, best = 0;
  for (let r = 0; r < s.length; r++) {
    const c = s[r];
    const prev = lastIdx.get(c);
    if (prev !== undefined && prev >= l) l = prev + 1;
    lastIdx.set(c, r);
    if (r - l + 1 > best) best = r - l + 1;
  }
  return best;
}
